diff --git a/llvm/lib/Analysis/ScalarEvolution.cpp b/llvm/lib/Analysis/ScalarEvolution.cpp
index 4dcf884823a61..3bb9c93deb0b3 100644
--- a/llvm/lib/Analysis/ScalarEvolution.cpp
+++ b/llvm/lib/Analysis/ScalarEvolution.cpp
@@ -6777,6 +6777,15 @@ const ConstantRange &ScalarEvolution::getRangeRef(
   }
   case scAddExpr: {
     const SCEVAddExpr *Add = cast<SCEVAddExpr>(S);
+    // Check if this is a URem pattern: A - (A / B) * B, which is always < B.
+    const SCEV *URemLHS = nullptr, *URemRHS = nullptr;
+    if (SignHint == ScalarEvolution::HINT_RANGE_UNSIGNED &&
+        match(S, m_scev_URem(m_SCEV(URemLHS), m_SCEV(URemRHS), *this))) {
+      ConstantRange LHSRange = getRangeRef(URemLHS, SignHint, Depth + 1);
+      ConstantRange RHSRange = getRangeRef(URemRHS, SignHint, Depth + 1);
+      ConservativeResult =
+          ConservativeResult.intersectWith(LHSRange.urem(RHSRange), RangeType);
+    }
     ConstantRange X = getRangeRef(Add->getOperand(0), SignHint, Depth + 1);
     unsigned WrapType = OBO::AnyWrap;
     if (Add->hasNoSignedWrap())

tests.test_body:
define i8 @urem_var_divisor_ugt_0_ult_10(i8 %a, i8 range(i8 1, 10) %d) {
  %t0 = urem i8 %a, %d
  ret i8 %t0
}

define i8 @urem_var_divisor_ult_10(i8 %a, i8 range(i8 0, 10) %d) {
  %t0 = urem i8 %a, %d
  ret i8 %t0
}

define i8 @urem_var_divisor_unknown(i8 %a, i8 %d) {
  %t0 = urem i8 %a, %d
  ret i8 %t0
}

define i8 @urem_var_divisor_ugt_1_ult_10(i8 %a, i8 range(i8 2, 10) %d) {
  %t0 = urem i8 %a, %d
  ret i8 %t0
}

define i8 @foo(i8 %a) {
  %t0 = urem i8 %a, 27
  ret i8 %t0
}

define i8 @urem_var_divisor_signed(i8 %a, i8 range(i8 -19, 10) %d) {
  %t0 = urem i8 %a, %d
  ret i8 %t0
}

define i32 @test_trunc_zext(i32 %arg) {
  %trunc = trunc i32 %arg to i3
  %zext = zext i3 %trunc to i32
  %sub = sub i32 %arg, %zext
  ret i32 %sub
}
